__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size - 1 - t) {
        m_dev[size * (globalId + t + 1) + t] = a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -= m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -= m_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] * b_dev[t];
        }
    }
}

void InitPerRun(int size, float *m) {
    for (int i = 0; i < size * size; i++) {
        m[i] = 0.0f;
    }
}

void ForwardSub(float *a, float *b, float *m, int size) {
    int threadsFan1 = 256;
    int blocksFan1 = (size + threadsFan1 - 1) / threadsFan1;

    dim3 threadsFan2(16, 16);
    dim3 blocksFan2((size + threadsFan2.x - 1) / threadsFan2.x, (size + threadsFan2.y - 1) / threadsFan2.y);

    float *a_dev, *b_dev, *m_dev;

    cudaMalloc((void **)&a_dev, sizeof(float) * size * size);
    cudaMalloc((void **)&b_dev, sizeof(float) * size);
    cudaMalloc((void **)&m_dev, sizeof(float) * size * size);

    cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice);
    cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice);
    cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice);

    for (int t = 0; t < size - 1; t++) {
        Fan1<<<blocksFan1, threadsFan1>>>(m_dev, a_dev, b_dev, size, t);
        cudaDeviceSynchronize();

        Fan2<<<blocksFan2, threadsFan2>>>(m_dev, a_dev, b_dev, size, t);
        cudaDeviceSynchronize();
    }

    cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
    cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost);
    cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);

    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    for (int i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (int j = 0; j < i; j++) {
            finalVec[size - i - 1] -= a[size * (size - i - 1) + (size - j - 1)] * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] /= a[size * (size - i - 1) + (size - i - 1)];
    }
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            fscanf(fp, "%f", ary + size * i + j);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            printf("%8.2f ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        printf("%.2f ", ary[i]);
    }
    printf("\n");
}

int main() {
    int Size;
    char filename[30];
    printf("Enter the data file name: ");
    scanf("%29s", filename);
    printf("The file name is: %s\n", filename);

    FILE *fp = fopen(filename, "r");
    if (!fp) {
        printf("Failed to open file %s\n", filename);
        return -1;
    }

    fscanf(fp, "%d", &Size);

    float *a = (float *)malloc(Size * Size * sizeof(float));
    InitMat(fp, Size, a, Size, Size);
    printf("The input matrix a is:\n");
    PrintMat(a, Size, Size, Size);

    float *b = (float *)malloc(Size * sizeof(float));
    InitAry(fp, b, Size);
    printf("The input array b is:\n");
    PrintAry(b, Size);

    fclose(fp);

    float *m = (float *)malloc(Size * Size * sizeof(float));
    InitPerRun(Size, m);

    ForwardSub(a, b, m, Size);

    printf("The result of matrix m is: \n");
    PrintMat(m, Size, Size, Size);
    printf("The result of matrix a is: \n");
    PrintMat(a, Size, Size, Size);
    printf("The result of array b is: \n");
    PrintAry(b, Size);

    float *finalVec = (float *)malloc(Size * sizeof(float));
    BackSub(a, b, finalVec, Size);
    printf("The final solution is: \n");
    PrintAry(finalVec, Size);

    free(a);
    free(b);
    free(m);
    free(finalVec);

    return 0;
}
